arguments.file_text:
@page "/catalog"
@using sv_b8af2f4cdebf4719a30579a0e6a2f1a4.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-page">
    <aside class="catalog-sidebar">
        <CatalogFilters Categories="@_categories"
                        OnFiltersApplied="HandleFiltersApplied"
                        OnFiltersCleared="HandleFiltersCleared" />
    </aside>

    <main class="catalog-main">
        @if (_errorMessage is not null)
        {
            <div class="catalog-error">
                <p>⚠ @_errorMessage</p>
                <button @onclick="RetryLoad">Retry</button>
            </div>
        }
        else if (_isLoading)
        {
            <div class="catalog-loading">
                <p>Loading products…</p>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="catalog-empty">
                <p>No products match your criteria.</p>
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="@_result.TotalCount"
                            Page="@_currentPage"
                            PageSize="@PageSize"
                            OnSortChanged="HandleSortChanged" />

            <div class="product-grid">
                @foreach (var product in _result.Items)
                {
                    <ProductCard Product="@product"
                                 OnProductSelected="HandleProductSelected"
                                 OnAddToCart="HandleAddToCart" />
                }
            </div>

            @if (TotalPages > 1)
            {
                <CatalogPagination CurrentPage="@_currentPage"
                                   TotalPages="@TotalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        }
    </main>
</div>

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? _categories;
    private PagedResult<Product>? _result;
    private ProductFilter _currentFilter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private bool _isLoading = true;
    private string? _errorMessage;

    private int TotalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        _isLoading = true;
        _errorMessage = null;

        try
        {
            if (_categories is null)
            {
                _categories = await ProductService.GetCategoriesAsync();
            }

            _result = await ProductService.SearchAsync(_currentFilter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            _isLoading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        _currentFilter = filter;
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleFiltersCleared()
    {
        _currentFilter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

.catalog-page {
    display: flex;
    gap: 1.5rem;
    padding: 1.5rem;
    max-width: 1400px;
    margin: 0 auto;
}

.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 1rem;
}

.catalog-loading,
.catalog-empty,
.catalog-error {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 3rem;
    text-align: center;
    color: #666;
    background: #f9f9f9;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
}

.catalog-error {
    color: #c0392b;
    border-color: #e74c3c;
    background: #fdf0ef;
}

.catalog-error button {
    margin-top: 1rem;
    padding: 0.5rem 1.5rem;
    background: #e74c3c;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.catalog-error button:hover {
    background: #c0392b;
}

@media (max-width: 768px) {
    .catalog-page {
        flex-direction: column;
    }

    .catalog-sidebar {
        flex: none;
        width: 100%;
    }
}

