toolArgs.file_text:
.catalog-page {
    display: flex;
    gap: 1.5rem;
    padding: 1.5rem;
    max-width: 1400px;
    margin: 0 auto;
}

.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 1rem;
}

.catalog-loading,
.catalog-empty,
.catalog-error {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 3rem;
    text-align: center;
    color: #666;
    background: #f9f9f9;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
}

.catalog-error {
    color: #c0392b;
    border-color: #e74c3c;
    background: #fdf0ef;
}

.catalog-error button {
    margin-top: 1rem;
    padding: 0.5rem 1.5rem;
    background: #e74c3c;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.catalog-error button:hover {
    background: #c0392b;
}

@media (max-width: 768px) {
    .catalog-page {
        flex-direction: column;
    }

    .catalog-sidebar {
        flex: none;
        width: 100%;
    }
}

